import 'package:mirror_scorpion_key_generator/services/premium_verification_service.dart';\n\n/// Service to integrate activation codes with Mirror Scorpion Translate V2\nclass CodeIntegrationService {\n  static final CodeIntegrationService _instance = CodeIntegrationService._internal();\n  final PremiumVerificationService _verificationService = PremiumVerificationService();\n\n  factory CodeIntegrationService() => _instance;\n  CodeIntegrationService._internal();\n\n  /// Validate code from Mirror Scorpion Translate\n  Future<ValidationResponse> validateCodeForTranslate({\n    required String activationCode,\n    required String deviceId,\n    required DateTime codeGeneratedAt,\n  }) async {\n    try {\n      // Step 1: Check code format\n      if (!_verificationService.verifyCodeFormat(activationCode)) {\n        return ValidationResponse(\n          isValid: false,\n          message: 'صيغة الكود غير صحيحة',\n          errorCode: 'INVALID_FORMAT',\n        );\n      }\n\n      // Step 2: Validate code authenticity\n      if (!_verificationService.validateCode(activationCode, deviceId)) {\n        return ValidationResponse(\n          isValid: false,\n          message: 'معرّف الجهاز غير متطابق',\n          errorCode: 'DEVICE_MISMATCH',\n        );\n      }\n\n      // Step 3: Check expiration\n      final duration = _verificationService.extractDurationFromCode(activationCode);\n      final expirationDate = codeGeneratedAt.add(Duration(days: duration * 30));\n      final now = DateTime.now();\n\n      if (now.isAfter(expirationDate)) {\n        return ValidationResponse(\n          isValid: false,\n          message: 'انتهت صلاحية الكود',\n          errorCode: 'EXPIRED',\n          expirationDate: expirationDate,\n          daysRemaining: 0,\n        );\n      }\n\n      // Step 4: Extract license info\n      final daysRemaining = expirationDate.difference(now).inDays;\n      final licenseType = _getLicenseType(duration);\n\n      return ValidationResponse(\n        isValid: true,\n        message: 'تم التحقق بنجاح من الكود',\n        errorCode: null,\n        licenseType: licenseType,\n        expirationDate: expirationDate,\n        daysRemaining: daysRemaining,\n        duration: duration,\n      );\n    } catch (e) {\n      return ValidationResponse(\n        isValid: false,\n        message: 'حدث خطأ: ${e.toString()}',\n        errorCode: 'VERIFICATION_ERROR',\n      );\n    }\n  }\n\n  /// Get premium features based on code\n  PremiumFeatures getPremiumFeatures(String activationCode) {\n    final duration = _verificationService.extractDurationFromCode(activationCode);\n    \n    return PremiumFeatures(\n      unlimitedTranslations: true,\n      offlineMode: true,\n      customDictionary: true,\n      advancedSettings: true,\n      noAds: true,\n      cloudSync: true,\n      apiAccess: true,\n      prioritySupport: true,\n      durationMonths: duration,\n    );\n  }\n\n  /// Get license type\n  String _getLicenseType(int durationMonths) {\n    switch (durationMonths) {\n      case 3:\n        return 'QUARTERLY';\n      case 12:\n        return 'ANNUAL';\n      default:\n        return 'MONTHLY';\n    }\n  }\n\n  /// Extract code info for display\n  CodeInfo extractCodeInfo(String code) {\n    final deviceId = _verificationService.extractDeviceIdFromCode(code);\n    final duration = _verificationService.extractDurationFromCode(code);\n\n    return CodeInfo(\n      code: code,\n      deviceId: deviceId ?? 'Unknown',\n      duration: duration,\n      durationLabel: _getDurationLabel(duration),\n      licenseType: _getLicenseType(duration),\n    );\n  }\n\n  /// Get duration label\n  String _getDurationLabel(int months) {\n    switch (months) {\n      case 3:\n        return '3 أشهر';\n      case 12:\n        return 'سنة واحدة';\n      default:\n        return 'شهر واحد';\n    }\n  }\n}\n\n/// Validation response model\nclass ValidationResponse {\n  final bool isValid;\n  final String message;\n  final String? errorCode;\n  final String? licenseType;\n  final DateTime? expirationDate;\n  final int? daysRemaining;\n  final int? duration;\n\n  ValidationResponse({\n    required this.isValid,\n    required this.message,\n    this.errorCode,\n    this.licenseType,\n    this.expirationDate,\n    this.daysRemaining,\n    this.duration,\n  });\n\n  /// Convert to JSON\n  Map<String, dynamic> toJson() {\n    return {\n      'isValid': isValid,\n      'message': message,\n      'errorCode': errorCode,\n      'licenseType': licenseType,\n      'expirationDate': expirationDate?.toIso8601String(),\n      'daysRemaining': daysRemaining,\n      'duration': duration,\n    };\n  }\n\n  /// Create from JSON\n  factory ValidationResponse.fromJson(Map<String, dynamic> json) {\n    return ValidationResponse(\n      isValid: json['isValid'] as bool,\n      message: json['message'] as String,\n      errorCode: json['errorCode'] as String?,\n      licenseType: json['licenseType'] as String?,\n      expirationDate: json['expirationDate'] != null\n          ? DateTime.parse(json['expirationDate'] as String)\n          : null,\n      daysRemaining: json['daysRemaining'] as int?,\n      duration: json['duration'] as int?,\n    );\n  }\n}\n\n/// Premium features model\nclass PremiumFeatures {\n  final bool unlimitedTranslations;\n  final bool offlineMode;\n  final bool customDictionary;\n  final bool advancedSettings;\n  final bool noAds;\n  final bool cloudSync;\n  final bool apiAccess;\n  final bool prioritySupport;\n  final int durationMonths;\n\n  PremiumFeatures({\n    required this.unlimitedTranslations,\n    required this.offlineMode,\n    required this.customDictionary,\n    required this.advancedSettings,\n    required this.noAds,\n    required this.cloudSync,\n    required this.apiAccess,\n    required this.prioritySupport,\n    required this.durationMonths,\n  });\n\n  /// Convert to JSON\n  Map<String, dynamic> toJson() {\n    return {\n      'unlimitedTranslations': unlimitedTranslations,\n      'offlineMode': offlineMode,\n      'customDictionary': customDictionary,\n      'advancedSettings': advancedSettings,\n      'noAds': noAds,\n      'cloudSync': cloudSync,\n      'apiAccess': apiAccess,\n      'prioritySupport': prioritySupport,\n      'durationMonths': durationMonths,\n    };\n  }\n}\n\n/// Code info model\nclass CodeInfo {\n  final String code;\n  final String deviceId;\n  final int duration;\n  final String durationLabel;\n  final String licenseType;\n\n  CodeInfo({\n    required this.code,\n    required this.deviceId,\n    required this.duration,\n    required this.durationLabel,\n    required this.licenseType,\n  });\n\n  /// Convert to JSON\n  Map<String, dynamic> toJson() {\n    return {\n      'code': code,\n      'deviceId': deviceId,\n      'duration': duration,\n      'durationLabel': durationLabel,\n      'licenseType': licenseType,\n    };\n  }\n}\n"
